    """Select a tip key from TIPS, optionally biased by self.tip_weights."""
    keys = list(TIPS.keys())

    if not self.tip_weights:
        return self.rng.choice(keys)

    weights = [max(self.tip_weights.get(key, 1.0), 0.0) for key in keys]
    total = sum(weights)
    if total <= 0:
        return self.rng.choice(keys)

    threshold = self.rng.random()
    cumulative = 0.0
    for key, weight in zip(keys, weights):
        cumulative += weight / total
        if threshold < cumulative:
